package com.xoxo.pos.auth;
import com.xoxo.pos.security.JwtService;import com.xoxo.pos.users.*;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.web.bind.annotation.*;import java.util.Map;
@RestController @RequestMapping("/api/auth") public class AuthController{private final UserRepository users;private final PasswordEncoder enc;private final JwtService jwt;public AuthController(UserRepository users,PasswordEncoder enc,JwtService jwt){this.users=users;this.enc=enc;this.jwt=jwt;}@PostMapping("/setup-admin") public Map<String,Object> setup(){if(!users.existsByUsername("admin"))users.save(new UserEntity("admin",enc.encode("admin123"),Role.ADMIN,true));return Map.of("username","admin","password","admin123");}@PostMapping("/login") public LoginResponse login(@RequestBody LoginRequest r){var u=users.findByUsernameAndActiveTrue(r.username()).orElseThrow(()->new RuntimeException("Usuario no encontrado"));if(!enc.matches(r.password(),u.getPassword()))throw new RuntimeException("Contraseña incorrecta");return new LoginResponse(jwt.generate(u.getUsername(),u.getRole()),u.getUsername(),u.getRole().name());}}
